sql:
SELECT COUNT(*) AS total_spoiled_ballots
FROM spoiled_ballots
WHERE spoiled_ballot_type = 'in-person' AND election_id = 1;

SELECT COUNT(write_in_count) AS total_write_in_votes
FROM write_in_votes
WHERE election_id = 0 AND write_in_vote_type = 'absentee';

SELECT AVG(share_count) AS avg_vote_share
FROM vote_shares
WHERE vote_share_type = 'in-person';

external_knowledge:
Top precincts refer to the top 4 precincts ranked by total votes or total spoiled ballots in descending order; 
"most votes" means the highest total_votes value; 
"most spoiled ballots" means the highest total_spoiled value.

sql:
SELECT spoiled_count, spoiled_ballot_reason
FROM spoiled_ballots
WHERE election_id = 0;

SELECT write_in_vote_type, SUM(write_in_count) AS total_write_in_votes
FROM write_in_votes
GROUP BY write_in_vote_type;

SELECT voter_name, voter_date_of_birth
FROM voters
ORDER BY voter_date_of_birth ASC;

SELECT precinct_id, SUM(spoiled_count) AS total_spoiled_ballots
FROM spoiled_ballots
GROUP BY precinct_id;

SELECT share_count, vote_share_type
FROM vote_shares
WHERE election_id = 0;
